__kernel void compute_distances(
    __global const char* sandbox,
    __global float* z,
    const float target_lat,
    const float target_long,
    const int rec_count)
{
    int i = get_global_id(0);
    if(i < rec_count) {
        int base_idx = i * 49 + 27; // LATITUDE_POS - 1 = 27
        // Parse latitude string (5 chars) to float
        // Approximate atof by parsing directly
        // We assume fixed format: latitude at sandbox[base_idx .. base_idx+4]
        // and longitude at sandbox[base_idx+5 .. base_idx+9]
        // We will convert these substrings to floats.

        // Convert latitude substring
        float tmp_lat = 0.0f;
        float lat_sign = 1.0f;
        int idx = base_idx;
        if(sandbox[idx] == '-') {
            lat_sign = -1.0f;
            idx++;
        }
        // parse integer part and decimal part
        float lat_int = 0.0f;
        float lat_frac = 0.0f;
        int frac_div = 1;
        int decimal_found = 0;
        for(int c=0; c<5; c++) {
            char ch = sandbox[idx+c];
            if(ch == '.' ) {
                decimal_found = 1;
            } else if(ch >= '0' && ch <= '9') {
                int digit = ch - '0';
                if(decimal_found == 0) {
                    lat_int = lat_int * 10.0f + (float)digit;
                } else {
                    lat_frac = lat_frac * 10.0f + (float)digit;
                    frac_div *= 10;
                }
            }
        }
        tmp_lat = lat_sign * (lat_int + lat_frac/(float)frac_div);

        // Convert longitude substring
        float tmp_long = 0.0f;
        float long_sign = 1.0f;
        idx = base_idx + 5;
        if(sandbox[idx] == '-') {
            long_sign = -1.0f;
            idx++;
        }
        float long_int = 0.0f;
        float long_frac = 0.0f;
        frac_div = 1;
        decimal_found = 0;
        for(int c=0; c<5; c++) {
            char ch = sandbox[idx+c];
            if(ch == '.') {
                decimal_found = 1;
            } else if(ch >= '0' && ch <= '9') {
                int digit = ch - '0';
                if(decimal_found == 0) {
                    long_int = long_int * 10.0f + (float)digit;
                } else {
                    long_frac = long_frac * 10.0f + (float)digit;
                    frac_div *= 10;
                }
            }
        }
        tmp_long = long_sign * (long_int + long_frac/(float)frac_div);

        float dx = tmp_lat - target_lat;
        float dy = tmp_long - target_long;
        z[i] = sqrt(dx*dx + dy*dy);
    }
}
